218	      }
219	      if (session.project_id !== projectId) {
220	        return jsonToolResult(
221	          errorPayload(ERROR_CODES.PROJECT_MISMATCH, SPEC_ERROR_MESSAGES[ERROR_CODES.PROJECT_MISMATCH]),
222	          true
223	        );
224	      }
225	
226	      return runtime.locks.withLock(session.claude_session_id, async () => {
227	        const lockedSession = runtime.db.getSession(input.session_id);
228	        if (!lockedSession) {
229	          return jsonToolResult(
230	            errorPayload(ERROR_CODES.SESSION_NOT_FOUND, SPEC_ERROR_MESSAGES[ERROR_CODES.SESSION_NOT_FOUND]),
231	            true
232	          );
233	        }
234	        if (lockedSession.project_id !== projectId) {
235	          return jsonToolResult(
236	            errorPayload(ERROR_CODES.PROJECT_MISMATCH, SPEC_ERROR_MESSAGES[ERROR_CODES.PROJECT_MISMATCH]),
237	            true
238	          );
239	        }
240	
241	        runtime.db.archiveSession(input.session_id, input.reason);
242	        return jsonToolResult({
243	          ok: true,
244	          status: "archived"
245	        });
246	      });
247	    }
